(window.webpackJsonp=window.webpackJsonp||[]).push([[1240],{1535:function(n){n.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * Definition for a binary tree node.\\n * function TreeNode(val) {\\n *     this.val = val;\\n *     this.left = this.right = null;\\n * }\\n */</span>\\n<span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{TreeNode}</span> <span class=\\"hljs-variable\\">root1</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{TreeNode}</span> <span class=\\"hljs-variable\\">root2</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{boolean}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> leafSimilar = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">root1, root2</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> leaf1=getLeaf(root1),\\n      leaf2=getLeaf(root2)\\n  <span class=\\"hljs-keyword\\">return</span> leaf1.toString()===leaf2.toString()\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">getLeaf</span>(<span class=\\"hljs-params\\">root</span>)</span>{\\n    <span class=\\"hljs-keyword\\">if</span>(!root)<span class=\\"hljs-keyword\\">return</span> []\\n    <span class=\\"hljs-keyword\\">let</span> res=[]\\n    <span class=\\"hljs-keyword\\">if</span>(root.left)res=res.concat(getLeaf(root.left))\\n    <span class=\\"hljs-keyword\\">if</span>(root.right)res=res.concat(getLeaf(root.right))\\n    <span class=\\"hljs-keyword\\">if</span>(!root.left &amp;&amp; !root.right){\\n      res.push(root.val)\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> res\\n  }\\n};\\n</code></pre>\\n"],"titleSlug":"leaf-similar-trees","hasThinking":false,"content":"<p>\u8bf7\u8003\u8651\u4e00\u68f5\u4e8c\u53c9\u6811\u4e0a\u6240\u6709\u7684\u53f6\u5b50\uff0c\u8fd9\u4e9b\u53f6\u5b50\u7684\u503c\u6309\u4ece\u5de6\u5230\u53f3\u7684\u987a\u5e8f\u6392\u5217\u5f62\u6210\u4e00\u4e2a\xa0<strong>\u53f6\u503c\u5e8f\u5217 </strong>\u3002</p>\\n\\n<p><img alt=\\"\\" src=\\"https://s3-lc-upload.s3.amazonaws.com/uploads/2018/07/16/tree.png\\" style=\\"height: 240px; width: 300px;\\" /></p>\\n\\n<p>\u4e3e\u4e2a\u4f8b\u5b50\uff0c\u5982\u4e0a\u56fe\u6240\u793a\uff0c\u7ed9\u5b9a\u4e00\u68f5\u53f6\u503c\u5e8f\u5217\u4e3a\xa0<code>(6, 7, 4, 9, 8)</code>\xa0\u7684\u6811\u3002</p>\\n\\n<p>\u5982\u679c\u6709\u4e24\u68f5\u4e8c\u53c9\u6811\u7684\u53f6\u503c\u5e8f\u5217\u662f\u76f8\u540c\uff0c\u90a3\u4e48\u6211\u4eec\u5c31\u8ba4\u4e3a\u5b83\u4eec\u662f\xa0<em>\u53f6\u76f8\u4f3c\xa0</em>\u7684\u3002</p>\\n\\n<p>\u5982\u679c\u7ed9\u5b9a\u7684\u4e24\u4e2a\u6839\u7ed3\u70b9\u5206\u522b\u4e3a\xa0<code>root1</code> \u548c\xa0<code>root2</code>\xa0\u7684\u6811\u662f\u53f6\u76f8\u4f3c\u7684\uff0c\u5219\u8fd4\u56de\xa0<code>true</code>\uff1b\u5426\u5219\u8fd4\u56de <code>false</code> \u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode.com/uploads/2020/09/03/leaf-similar-1.jpg\\" style=\\"height: 297px; width: 750px;\\" /></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>root1 = [3,5,1,6,2,9,8,null,null,7,4], root2 = [3,5,1,6,7,4,2,null,null,null,null,null,null,9,8]\\n<strong>\u8f93\u51fa\uff1a</strong>true\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>root1 = [1], root2 = [1]\\n<strong>\u8f93\u51fa\uff1a</strong>true\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>root1 = [1], root2 = [2]\\n<strong>\u8f93\u51fa\uff1a</strong>false\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>root1 = [1,2], root2 = [2,2]\\n<strong>\u8f93\u51fa\uff1a</strong>true\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 5\uff1a</strong></p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode.com/uploads/2020/09/03/leaf-similar-2.jpg\\" style=\\"height: 165px; width: 450px;\\" /></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>root1 = [1,2,3], root2 = [1,3,2]\\n<strong>\u8f93\u51fa\uff1a</strong>false\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li>\u7ed9\u5b9a\u7684\u4e24\u68f5\u6811\u53ef\u80fd\u4f1a\u6709\xa0<code>1</code>\xa0\u5230 <code>200</code>\xa0\u4e2a\u7ed3\u70b9\u3002</li>\\n\\t<li>\u7ed9\u5b9a\u7684\u4e24\u68f5\u6811\u4e0a\u7684\u503c\u4ecb\u4e8e <code>0</code> \u5230 <code>200</code> \u4e4b\u95f4\u3002</li>\\n</ul>\\n","title":"872. \u53f6\u5b50\u76f8\u4f3c\u7684\u6811","relatedTags":["\u6811","\u6df1\u5ea6\u4f18\u5148\u641c\u7d22"],"difficult":"Easy","lang":["javascript"],"uniqueID":"872"}')}}]);